import{_ as r,o as t,c as p,j as e,a as d,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const T=JSON.parse('{"title":"TMD2024款圣诞树","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/TMD2024款圣诞树.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/TMD2024款圣诞树.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/TMD2024款圣诞树.md"};function o(l,a,_,i,c,b){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"tmd2024款圣诞树",tabindex:"-1"},[d("TMD2024款圣诞树 "),e("a",{class:"header-anchor",href:"#tmd2024款圣诞树","aria-label":'Permalink to "TMD2024款圣诞树"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="tmd2024款圣诞树-1" tabindex="-1">TMD2024款圣诞树 <a class="header-anchor" href="#tmd2024款圣诞树-1" aria-label="Permalink to &quot;TMD2024款圣诞树&quot;">​</a></h1><p>TMD2024款圣诞树<br> 价格：750<br> 主神空间里节日气氛满满的圣诞树，上面挂满了轮回者、管理者以及主神的祝福，但不知道被谁记录了下来，打算批量复制拿来当武器出售</p><p>==========<br> 【圣诞树情况一览】<br> ————现在<br> #因为管理的权限，变得很大（为了方便持握已经等比例恢复）</p><p>#高处有一个作家徽章</p><p>#树枝上挂着单片眼镜，两堆不同的硬币，一树转生苹果【备注：蛾子娘和绿毛小丑请客】，普通但好看的彩灯，红灯笼，一堆弹壳，一袋奶牛色布偶猫（哈基米已安全转移）</p><p>#树干上被人用黑暗暗哉佩利敖光线刻上了黑暗能量，部分结晶化</p><p>#树下的礼物盒里放着希尔薇魔改版【可结婚】，可以玩希尔薇的手机，一叠期末试卷</p><p>#以上挂件皆做了加固处理，不用担心掉落，回到主神空间后会自动补齐（不用想着摘下来使用，皆为样品）</p><p>————曾经<br> #被涂上了魂五小零食，已被清洗（主神100%保证使用者和被攻击者的身心安全）</p><p>#树枝上挂着fufu，不知道被谁拿走了</p><p>#树下放着ns和宝可梦朱，不知道被谁拿走了<br> ==========</p><p>【圣诞快乐！】：“这只是一颗圣诞树，对吧？”“#意义不明的笑”“只是圣诞树，对吧？”“#毫不掩饰的笑”由于圣诞树一般很难跟武器联想起来，因此在拥有类似圣诞节文化的影片中，其他人看来这颗圣诞树只会是略怪一些的树罢了，不过会很引人注意。<br> 即使没有，扛着颗装扮奇特的树也很难被认为是武器，但可能会带来别的麻烦。如果你当别人的面使用它攻击，就更麻烦了。<br> 任何人在看到这把武器第一眼都可以过一个dc2的智力检定，一旦成功便发现这是一把可以用来砸人的武器，如果没有成功，那么在你第一次用圣诞树攻击该目标时都视为无支线措手不及。</p><p>【俺寻思这可以当棍使】：TMD204款圣诞树可视为武器伤害3L，具有【长柄】【双手】【重型武器】【格挡1】，体积6的长棍</p><p>【随用随取，好评满满】：购买圣诞树后，会附赠一个专门存放圣诞树和其他圣诞用品的3立方米空间，只能用来装一些小杂物（圣诞礼物），每次放入/取出都需要一个移动动作。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}co